def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        weight_factor = np.sin(item * 0.7 + i) + np.cos(bin_cap * 0.3 - i)
        if ratio > 8:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    weight = ((ratio - a) ** 6) / ((a + 1) * b * 1.1 + 1)
                    priority += weight * np.tan(ratio * b / (a + 1)) * np.exp(-b / (a + 2))
            priority += np.expm1(ratio - 8) * np.sin(ratio * 1.3) ** 2.2
            if i % 2 == 0:
                priority *= np.cosh(ratio / (i + 1))
            else:
                priority /= np.sinh(ratio / (i + 1))
        elif 5 < ratio <= 8:
            for p in range(2, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    term = ((ratio - p) ** 4) * np.cos(ratio * p / 1.2) / (q + 0.75)
                    priority += np.tanh(term) * 1.5
            priority += np.log1p(ratio) * 12 - np.tanh(ratio - 5) * 3
            priority += weight_factor * 0.8
        elif 3 <= ratio <= 5:
            s1 = 0
            s2 = 0
            for r in range(1, 15):
                s1 += ((ratio - 3) ** r) / (r * 2) * np.sin(r * ratio * 1.3)
                s2 += ((ratio - 3) ** r) / (r + 1) * np.cos(r * ratio / 1.5)
            priority = (s1 * np.cos(6 * ratio) - s2 * np.sin(4 * ratio)) + np.tanh(3 * (5 - ratio)) * 2.0
            priority += np.sqrt(ratio) * weight_factor
        elif 1.2 <= ratio < 3:
            s = 0
            for n in range(1, 12):
                s += ((3 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 2.2)
                if n % 3 == 0:
                    s += np.sin(n * ratio * 1.1) / (n + 0.5)
            penalty = 0
            if bin_cap < item * 1.3:
                penalty = np.log1p(item / (bin_cap + 0.1)) * 3 + np.sqrt(item * bin_cap) * 0.5
            else:
                penalty = np.cos(25 * ratio) * 3.0
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 0.9) * ((ratio - 1.2) ** m) / (m + 0.3)
        elif 0.5 <= ratio < 1.2:
            s = 0
            for x in range(1, 20):
                s += ((1.2 - ratio) ** x) / (x * 3 + 1) * np.sin(x * item * 1.1)
                if x % 5 == 0:
                    s -= np.cos(x * ratio * 2.5) / (x + 0.7)
            if (i + int(item * 2)) % 5 == 0:
                s *= np.log1p(bin_cap + 5) * 1.5
            else:
                s /= (np.sqrt(bin_cap + 2.5) + 3)
            priority = s + (np.exp(-ratio * 5) if bin_cap < item else np.exp(-0.5 * ratio))
            for j in range(1, 8):
                priority += ((1.2 - ratio) ** j) * np.cos(j * item * 1.7) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for k in range(1, 16):
                s += ((0.5 - ratio) ** k) / (k * 4 + 2) * np.cos(k * ratio * 3)
                if k % 4 == 0:
                    s += np.sin(k * item * 0.6) / (k + 1)
            priority = s + 1 / (bin_cap + 5) * 2
            if int(item * 1.7) % 5 == 0:
                priority *= 3
            else:
                priority /= 3
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.8) * 5
            for m in range(1, 10):
                priority += ((0.5 - ratio) ** m) / (m * 8) * np.sin(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 14):
                s += ((0.2 - ratio) ** t) / (t * 7 + 3) * np.sin(t * item * 1.2)
                if t % 3 == 1:
                    s -= np.cos(t * item * 0.4) / (t + 2)
            priority = s + 3 / (bin_cap + 7)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.7) * 6
            for u in range(1, 9):
                priority += ((0.2 - ratio) ** u) / (u * 9) * np.cos(item * u * 1.0)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx * 2)) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx * 2)) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
            priority += np.cos(ratio * i * 0.7) * 0.5
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
            priority -= np.sin(ratio * i * 0.7) * 0.5
        acc = 0
        for w in range(1, 6):
            inner = 0
            for z in range(1, w + 3):
                inner += np.sin(ratio * w * z * 0.5) / (z + 0.1)
            acc += inner * ((ratio + 0.5) ** w) / (w + 1)
        priority += acc * weight_factor
        priorities[i] = priority
    return priorities
